const assignmentStatusConfig = {
  offered: { bg: 'bg-amber-50', text: 'text-amber-700', border: 'border-l-amber-500' },
  accepted: { bg: 'bg-blue-50', text: 'text-blue-700', border: 'border-l-blue-500' },
  in_progress: { bg: 'bg-red-50', text: 'text-red-700', border: 'border-l-red-500' },
  completed: { bg: 'bg-emerald-50', text: 'text-emerald-700', border: 'border-l-emerald-500' },
  declined: { bg: 'bg-red-50', text: 'text-red-700', border: 'border-l-red-500' },
  cancelled: { bg: 'bg-gray-100', text: 'text-gray-600', border: 'border-l-gray-400' },
}

function parseStatesInput(v) { return v.split(/[,;\s]+/).map(s=>s.trim().toUpperCase()).filter(s=>s.length===2) }
function getOffers() { return assignments.filter(a=>a.status==='offered') }
function getTodayEarnings() {
  const today = new Date().toISOString().slice(0, 10)
  return assignments.filter(a=>a.status==='completed').reduce((s,a)=>{const b=bookingsById[a.booking_id];return s+(b?.booking_details?.preferred_date===today?b?.booking_details?.price||0:0)},0)
}
function getAcceptedJobs() { return assignments.filter(a=>a.status==='accepted'||a.status==='in_progress'||a.status==='completed') }
function getAcceptedBookings() { return getAcceptedJobs().map(a=>bookingsById[a.booking_id]).filter(Boolean) }
function getBookingForAssignment(a) { return bookingsById[a?.booking_id] }

function formatDate(dateStr) { if(!dateStr)return''; const d=new Date(dateStr+'T00:00:00'); return d.toLocaleDateString('en-US',{weekday:'short',month:'short',day:'numeric',year:'numeric'}) }
function formatDateTime(isoStr) { if(!isoStr)return''; const d=new Date(isoStr); return d.toLocaleString('en-US',{month:'short',day:'numeric',year:'numeric',hour:'numeric',minute:'2-digit'}) }
function formatMonth(date) { return date.toLocaleDateString('en-US',{month:'long',year:'numeric'}) }
function getDaysInMonth(y,m) { return new Date(y,m+1,0).getDate() }
function getFirstDayOfMonth(y,m) { return new Date(y,m,1).getDay() }
function getBookingsForDate(d) { return getAcceptedBookings().filter(b=>b.booking_details?.preferred_date===d) }
function groupBookingsByDate() { const m={}; getAcceptedBookings().forEach(b=>{const d=b.booking_details?.preferred_date;if(d){if(!m[d])m[d]=[];m[d].push(b)}});return m }
function isSameDay(d1,d2){return d1.getFullYear()===d2.getFullYear()&&d1.getMonth()===d2.getMonth()&&d1.getDate()===d2.getDate()}

function jobCard(booking,assignment){
  const{id,order_number,customer_info,location_info,booking_details,status}=booking
  const sc=statusConfig[status]||statusConfig.pending
  const hp=booking_details?.photo_url
  const aa=assignment?` data-assignment-id="${assignment.id}"`:''
  const isActive=status==='in_progress'
  const borderClass=isActive?'border-l-red-500 animate-pulse-ring':sc.border
  const statusDot=isActive?'bg-red-500':sc.dot
  const statusText=(status||'pending').replace('_',' ')
  const price=booking_details?.price||0
  return`<div class="job-card bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden mb-3 border-l-4 ${borderClass} active:scale-[0.98] transition-transform cursor-pointer" data-booking-id="${id}"${aa}><div class="p-4"><div class="flex items-center justify-between mb-2"><div class="flex items-center gap-2.5"><span class="text-[10px] font-semibold text-gray-400 uppercase tracking-wider">${location_info?.city||order_number||''}</span><span class="flex items-center gap-1"><span class="w-1.5 h-1.5 rounded-full ${statusDot}"></span><span class="text-[10px] font-medium text-gray-500 capitalize">${statusText}</span></span></div><span class="text-sm font-bold text-gray-900">$${price}</span></div><div class="flex items-start gap-3">${hp?`<img src="${hp}" class="w-10 h-10 rounded-lg object-cover shrink-0" alt="" loading="lazy" />`:`<div class="w-10 h-10 rounded-lg bg-gray-100 flex items-center justify-center shrink-0"><svg class="w-4 h-4 text-gray-400" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><rect x="3" y="3" width="18" height="18" rx="2" ry="2"/><circle cx="8.5" cy="8.5" r="1.5"/><polyline points="21 15 16 10 5 21"/></svg></div>`}<div class="min-w-0 flex-1"><p class="font-semibold text-gray-800 text-sm truncate">${customer_info?.name||'Unknown'}</p><p class="text-xs text-gray-400 mt-0.5">${booking_details?.service_type||'Service'} &middot; ${location_info?.city||''}, ${location_info?.state||''}</p><p class="text-[11px] text-gray-400 mt-0.5">${formatDate(booking_details?.preferred_date)} &middot; ${booking_details?.preferred_time||''}</p></div></div></div></div>`
}

function renderBookingDetail(booking,assignment){
  const{order_number,customer_info,location_info,booking_details,status,created_at}=booking
  const sc=statusConfig[status]||statusConfig.pending
  const serviceBadge=serviceTypeConfig[booking_details?.service_type]||'bg-gray-100 text-gray-700'
  const mapsUrl=`https://maps.google.com/?q=${encodeURIComponent([location_info?.address||'',location_info?.unit_number||'',location_info?.city||'',location_info?.state||'',location_info?.zip_code||''].filter(Boolean).join(' '))}`
  const asgnStatus=assignment?.status
  const showStartJob=asgnStatus==='accepted'
  const showCompleteJob=asgnStatus==='in_progress'
  return`<div class="absolute inset-0 z-[2000] bg-gray-100 flex flex-col animate-slide-up"><header class="bg-white border-b border-gray-100 text-gray-800 px-4 pt-3 pb-3 shrink-0"><div class="flex items-center gap-3"><button id="close-detail" class="w-8 h-8 bg-gray-100 rounded-lg flex items-center justify-center active:scale-90 transition-transform"><svg class="w-5 h-5 text-gray-500" viewBox="0 0 24 24">${iconsSvg.chevronLeft}</svg></button><div><h1 class="text-xs font-semibold leading-tight">${location_info?.city||''}, ${location_info?.state||''} &mdash; ${booking_details?.service_type||''}</h1></div></div></header>${showCompleteJob?`<div class="bg-red-600 px-4 py-4 flex items-center gap-3 shrink-0"><span class="relative flex h-3 w-3"><span class="animate-ping absolute inline-flex h-full w-full rounded-full bg-white opacity-75"></span><span class="relative inline-flex rounded-full h-3 w-3 bg-white"></span></span><span class="text-base font-bold text-white">Job In Progress</span></div>`:''}<main class="flex-1 overflow-y-auto pb-0">${booking_details?.photo_url?`<div class="h-48 bg-gray-200"><img src="${booking_details.photo_url}" class="w-full h-full object-cover" alt="" /></div>`:''}<div class="p-4 space-y-4 ${showCompleteJob?'pb-32':'pb-24'}"><div class="flex items-center justify-between bg-white rounded-xl p-4 shadow-sm border border-gray-100"><div class="flex items-center gap-3"><span class="text-xs px-2.5 py-1 rounded-full font-semibold ${sc.bg} ${sc.text} capitalize">${(status||'pending').replace('_',' ')}</span><span class="text-xs px-2.5 py-1 rounded-full font-medium ${serviceBadge}">${booking_details?.service_type||'Service'}</span></div><span class="text-xl font-bold text-gray-900">$${booking_details?.price||0}</span></div><div class="bg-white rounded-xl p-4 shadow-sm border border-gray-100"><h3 class="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-3">Customer</h3><p class="text-base font-semibold text-gray-800">${customer_info?.name||'Unknown'}</p>${customer_info?.email?`<a href="mailto:${customer_info.email}" class="flex items-center gap-2 text-sm text-gray-500 mt-2"><svg class="w-4 h-4" viewBox="0 0 24 24">${iconsSvg.mail}</svg><span>${customer_info.email}</span></a>`:''}${customer_info?.phone?`<a href="tel:${customer_info.phone.replace(/[^0-9+]/g,'')}" class="flex items-center gap-2 text-sm text-gray-500 mt-1.5"><svg class="w-4 h-4" viewBox="0 0 24 24">${iconsSvg.phone}</svg><span>${customer_info.phone}</span></a>`:''}</div><div class="bg-white rounded-xl p-4 shadow-sm border border-gray-100"><h3 class="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-3">Location</h3><a href="${mapsUrl}" target="_blank" rel="noopener" class="block text-sm text-brand hover:text-brand-700 active:text-brand-700 transition"><p>${location_info?.address||''}${location_info?.unit_number?' '+location_info.unit_number:''}</p><p>${location_info?.city||''},${location_info?.state||''} ${location_info?.zip_code||''}</p></a></div>${booking_details?.preferred_date||booking_details?.preferred_time?`<div class="bg-white rounded-xl p-4 shadow-sm border border-gray-100"><h3 class="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-3">Schedule</h3>${booking_details?.preferred_date?`<div class="flex items-center gap-2 text-sm text-gray-700"><svg class="w-4 h-4 text-gray-400" viewBox="0 0 24 24">${iconsSvg.calendar}</svg><span>${formatDate(booking_details.preferred_date)}</span></div>`:''}${booking_details?.preferred_time?`<div class="flex items-center gap-2 text-sm text-gray-700 mt-2"><svg class="w-4 h-4 text-gray-400" viewBox="0 0 24 24">${iconsSvg.clock}</svg><span>${booking_details.preferred_time}</span></div>`:''}</div>`:''}${booking_details?.estimated_items&&booking_details.estimated_items.length?`<div class="bg-white rounded-xl p-4 shadow-sm border border-gray-100"><h3 class="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-3">Items</h3>${booking_details.estimated_items.map(i=>`<div class="flex items-center gap-2 text-sm text-gray-700"><svg class="w-4 h-4 text-gray-400 shrink-0" viewBox="0 0 24 24">${iconsSvg.package}</svg><span>${i}</span></div>`).join('')}${booking_details?.estimated_volume?`<p class="text-xs text-gray-400 mt-2">${booking_details.estimated_volume}</p>`:''}</div>`:''}<div class="bg-white rounded-xl p-4 shadow-sm border border-gray-100"><h3 class="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-3">Details</h3><p class="text-sm text-gray-700 whitespace-pre-wrap">${booking_details?.details||'No additional details'}</p></div><p class="text-xs text-gray-400 text-center">Created ${formatDateTime(created_at)}</p></div></main>${showStartJob||showCompleteJob?`<div class="bg-white border-t border-gray-200 px-4 py-3 shrink-0 shadow-[0_-4px_12px_rgba(0,0,0,0.05)]">${showStartJob?`<button id="start-job-btn" class="w-full bg-brand text-white font-semibold py-3 rounded-xl hover:bg-secondary active:scale-[0.98] transition text-sm">Start Job</button>`:''}${showCompleteJob?`<button id="complete-job-btn" class="w-full bg-brand text-white font-semibold py-3 rounded-xl hover:bg-secondary active:scale-[0.98] transition text-sm">Mark Job Complete</button>`:''}</div>`:''}</div>`
}

async function loadDriverData(){
  loading=true;render()
  let driverRow=null
  const{data:rpcDriver,error:rpcError}=await supabase.rpc('get_my_driver')
  if(!rpcError&&rpcDriver)driverRow=rpcDriver
  else{const uid=session?.user?.id;if(uid){await supabase.rpc('register_driver',{p_full_name:'',p_phone:'',p_states:[]});const{data:linked}=await supabase.from('drivers').select('*').eq('user_id',uid).maybeSingle();driverRow=linked}}
  driver=driverRow||null
  if(driver){const{data:areas}=await supabase.from('driver_service_areas').select('state').eq('driver_id',driver.id).order('state');serviceAreas=(areas||[]).map(a=>a.state)}
  else{serviceAreas=[]}
  if(!driver||driver.status!=='approved'){assignments=[];bookingsById={};loading=false;render();return}
  const{data:assignmentRows}=await supabase.from('job_assignments').select('*').eq('driver_id',driver.id).order('assigned_at',{ascending:false})
  assignments=assignmentRows||[]
  const bookingIds=[...new Set(assignments.map(a=>a.booking_id))]
  if(bookingIds.length){const{data:bookingRows}=await supabase.from('bookings').select('*').in('id',bookingIds);bookingsById=Object.fromEntries((bookingRows||[]).map(b=>[b.id,b]))}
  else{bookingsById={}}
  loading=false;render()
}

function renderLoginPage(){
  document.querySelector('#app').innerHTML=`<div class="flex flex-col h-dvh max-w-md mx-auto bg-secondary relative overflow-hidden"><div class="absolute top-0 left-0 right-0 h-64 bg-secondary"></div><div class="absolute bottom-0 left-0 right-0 h-1/2 bg-gray-50"></div><div class="relative z-10 flex flex-col h-full"><div class="pt-20 pb-8 px-8 text-center text-white"><div class="flex items-end justify-center gap-1 mb-6"><span class="pl-bar" style="background:#fff;width:1.5rem;height:3.5rem;border-radius:2px"></span><span class="pl-bar pl-bar-2" style="background:#fff;width:1.5rem;height:3.5rem;border-radius:2px"></span></div><h1 class="text-2xl font-bold">Opek Junk Removal</h1><p class="text-brand-200 text-sm mt-1">Driver Dashboard</p></div><div class="flex-1 flex flex-col px-6 justify-center"><div class="bg-white rounded-2xl shadow-xl p-6">${authView==='login'?`<h2 class="text-lg font-bold text-gray-800 mb-6">Sign In</h2><form id="login-form" class="space-y-4"><div><label class="block text-xs font-medium text-gray-600 mb-1">Email</label><input type="email" id="login-email" placeholder="you@example.com" required class="w-full px-4 py-3 rounded-xl border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-brand focus:border-transparent transition" /></div><div><label class="block text-xs font-medium text-gray-600 mb-1">Password</label><input type="password" id="login-password" placeholder="Enter your password" required class="w-full px-4 py-3 rounded-xl border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-brand focus:border-transparent transition" /></div><p id="login-error" class="text-red-500 text-xs hidden"></p><button type="submit" class="w-full bg-brand text-white font-semibold py-3 rounded-xl hover:bg-secondary active:scale-[0.98] transition text-sm">Sign In</button></form><p class="text-center text-xs text-gray-500 mt-4">Don't have an account? <a href="#" id="switch-to-signup" class="text-brand font-medium">Sign Up</a></p>`:`<h2 class="text-lg font-bold text-gray-800 mb-6">Create Account</h2><form id="signup-form" class="space-y-4"><div><label class="block text-xs font-medium text-gray-600 mb-1">Full name</label><input type="text" id="signup-name" placeholder="Your name" required class="w-full px-4 py-3 rounded-xl border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-brand focus:border-transparent transition" /></div><div><label class="block text-xs font-medium text-gray-600 mb-1">Email</label><input type="email" id="signup-email" placeholder="you@example.com" required class="w-full px-4 py-3 rounded-xl border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-brand focus:border-transparent transition" /></div><div><label class="block text-xs font-medium text-gray-600 mb-1">Phone</label><input type="tel" id="signup-phone" placeholder="(555) 555-5555" class="w-full px-4 py-3 rounded-xl border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-brand focus:border-transparent transition" /></div><div><label class="block text-xs font-medium text-gray-600 mb-1">Service states</label><input type="text" id="signup-states" placeholder="CA, NV, AZ" required class="w-full px-4 py-3 rounded-xl border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-brand focus:border-transparent transition" /><p class="text-xs text-gray-400 mt-1">Comma-separated 2-letter state codes you cover</p></div><div><label class="block text-xs font-medium text-gray-600 mb-1">Password</label><input type="password" id="signup-password" placeholder="Min. 6 characters" required minlength="6" class="w-full px-4 py-3 rounded-xl border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-brand focus:border-transparent transition" /></div><p id="signup-error" class="text-red-500 text-xs hidden"></p><button type="submit" class="w-full bg-brand text-white font-semibold py-3 rounded-xl hover:bg-secondary active:scale-[0.98] transition text-sm">Create Account</button></form><p class="text-center text-xs text-gray-500 mt-4">Already have an account? <a href="#" id="switch-to-login" class="text-brand font-medium">Sign In</a></p>`}</div></div><p class="text-center text-xs text-gray-400 pb-6">Opek Junk Removal &copy; 2026</p></div></div>`
  setTimeout(()=>{
    if(authView==='login'){
      const f=document.getElementById('login-form');const e=document.getElementById('login-error')
      f.addEventListener('submit',async(ev)=>{ev.preventDefault();const em=document.getElementById('login-email').value;const pw=document.getElementById('login-password').value;e.classList.add('hidden');const{data,error}=await supabase.auth.signInWithPassword({email:em,password:pw});if(error){e.textContent=error.message;e.classList.remove('hidden')}else{session=data.session;renderApp();await loadDriverData()}})
    }else{
      const f=document.getElementById('signup-form');const e=document.getElementById('signup-error')
      f.addEventListener('submit',async(ev)=>{ev.preventDefault();const em=document.getElementById('signup-email').value;const pw=document.getElementById('signup-password').value;const nm=document.getElementById('signup-name').value;const ph=document.getElementById('signup-phone').value;const st=parseStatesInput(document.getElementById('signup-states').value);e.classList.add('hidden');const{data,error}=await supabase.auth.signUp({email:em,password:pw});if(error){e.textContent=error.message;e.classList.remove('hidden')}else{session=data.session;if(session){const{error:regError}=await supabase.rpc('register_driver',{p_full_name:nm,p_phone:ph,p_states:st});if(regError){e.textContent=regError.message;e.classList.remove('hidden');return};await loadDriverData()}else{e.textContent='Check your email to confirm your account, then sign in.';e.classList.remove('hidden')}}})
    }
    const ssu=document.getElementById('switch-to-signup');const sli=document.getElementById('switch-to-login')
    if(ssu)ssu.addEventListener('click',(ev)=>{ev.preventDefault();authView='signup';renderLoginPage()})
    if(sli)sli.addEventListener('click',(ev)=>{ev.preventDefault();authView='login';renderLoginPage()})
  },0)
}

function renderEmptyState(label,hint){
  const iconMap={Offers:iconsSvg.bell,Jobs:iconsSvg.briefcase,Schedule:iconsSvg.calendar,Settings:iconsSvg.cog}
  return`<div class="flex flex-col items-center justify-center h-full text-gray-400 px-6 py-12"><svg class="w-16 h-16 mb-4 text-gray-300" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1" stroke-linecap="round" stroke-linejoin="round">${iconMap[label]||iconMap['Jobs']}</svg><p class="text-lg font-medium text-gray-500">No ${label.toLowerCase()} yet</p><p class="text-sm text-gray-400 mt-1 text-center">${hint||`Your ${label.toLowerCase()} will appear here`}</p></div>`
}

function renderAppLoading(){return[1,2].map(()=>'<div class="bg-white rounded-xl shadow-sm border border-gray-100 p-4 animate-pulse mb-3"><div class="h-4 bg-gray-200 rounded w-24 mb-3"></div><div class="h-4 bg-gray-200 rounded w-32 mb-2"></div><div class="h-8 bg-gray-200 rounded w-full mt-4"></div></div>').join('')}

function renderPendingScreen(){
  const isPending=driver?.status==='pending';const isSuspended=driver?.status==='suspended';const noProfile=!driver
  return`<div class="flex flex-col items-center justify-center h-full px-6 py-12 text-center"><div class="w-16 h-16 rounded-full flex items-center justify-center mb-4 ${isSuspended?'bg-red-100':'bg-amber-100'}"><svg class="w-8 h-8 ${isSuspended?'text-red-600':'text-amber-600'}" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2">${iconsSvg.clock}</svg></div><h2 class="text-lg font-bold text-gray-800 mb-2">${noProfile?'Complete your profile':isSuspended?'Account suspended':'Pending approval'}</h2><p class="text-sm text-gray-500 max-w-xs">${noProfile?'Contact support to link your contractor account, or sign out and create a new driver account.':isSuspended?'Your driver account has been suspended. Contact Opek support for help.':'Your application is under review. You will see job offers here once an admin approves your account.'}</p>${driver&&serviceAreas.length?`<p class="text-xs text-gray-400 mt-4">Service areas: ${serviceAreas.join(', ')}</p>`:''}<button id="logout-btn" class="mt-8 text-sm text-red-600 font-medium">Sign out</button></div>`
}

function offerCard(assignment){
  const booking=getBookingForAssignment(assignment)
  if(!booking)return''
  const sc=assignmentStatusConfig.offered
  const sb=serviceTypeConfig[booking.booking_details?.service_type]||'bg-gray-100 text-gray-700'
  return`<div class="offer-card bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden mb-3 border-l-4 ${sc.border}" data-assignment-id="${assignment.id}"><div class="p-4"><div class="flex items-start justify-between mb-2"><div class="flex items-center gap-2"><span class="text-xs px-2 py-0.5 rounded-full font-medium ${sc.bg} ${sc.text}">New offer</span><span class="text-sm font-bold text-gray-800">${booking.location_info?.city||booking.order_number||''}</span></div></div><p class="font-semibold text-gray-800 mb-1">${booking.customer_info?.name||'Unknown'}</p><span class="inline-block text-xs px-1.5 py-0.5 rounded font-medium ${sb}">${booking.booking_details?.service_type||'Service'}</span><p class="text-xs text-gray-500 mt-2">${booking.location_info?.city||''},${booking.location_info?.state||''}</p><p class="text-xs text-gray-500">${formatDate(booking.booking_details?.preferred_date)} &middot; ${booking.booking_details?.preferred_time||''}</p>${assignment.note?`<p class="text-xs text-gray-400 mt-2 italic">"${assignment.note}"</p>`:''}<div class="flex gap-2 mt-4"><button class="accept-offer-btn flex-1 bg-brand text-white font-semibold py-2.5 rounded-xl text-sm active:scale-[0.98] transition" data-assignment-id="${assignment.id}">Accept</button><button class="decline-offer-btn flex-1 bg-gray-100 text-gray-700 font-semibold py-2.5 rounded-xl text-sm active:scale-[0.98] transition" data-assignment-id="${assignment.id}">Decline</button></div></div></div>`
}

function renderOffersContent(){const o=getOffers();if(!o.length)return renderEmptyState('Offers','New job offers from dispatch will appear here');return`<div class="mb-4"><span class="text-sm text-gray-500 font-medium">${o.length} pending offer${o.length!==1?'s':''}</span></div>${o.map(a=>offerCard(a)).join('')}`}

function renderJobsContent(){
  if(loading)return[1,2,3].map(()=>'<div class="bg-white rounded-xl shadow-sm border border-gray-100 p-4 animate-pulse mb-3"><div class="flex justify-between mb-3"><div class="h-4 bg-gray-200 rounded w-24"></div><div class="h-4 bg-gray-200 rounded w-12"></div></div><div class="flex gap-3 mb-3"><div class="h-12 w-12 bg-gray-200 rounded-lg shrink-0"></div><div class="flex-1"><div class="h-4 bg-gray-200 rounded w-32 mb-2"></div><div class="h-3 bg-gray-200 rounded w-20"></div></div></div><div class="flex gap-3"><div class="h-3 bg-gray-200 rounded w-16"></div><div class="h-3 bg-gray-200 rounded w-20"></div><div class="h-3 bg-gray-200 rounded w-28"></div></div></div>').join('')
  const o=getOffers();const accepted=getAcceptedJobs();const aBookings=getAcceptedBookings()
  if(!o.length&&!aBookings.length)return renderEmptyState('Jobs','Accepted jobs and new offers will appear here')
  let html='';let count=0
  if(o.length){html+=`<div class="mb-3"><span class="text-xs font-semibold text-amber-600 uppercase tracking-wider">${o.length} new offer${o.length!==1?'s':''}</span></div>${o.map(a=>offerCard(a)).join('')}`;count+=o.length}
  if(aBookings.length){const label=o.length?'Active jobs':`${accepted.length} job${accepted.length!==1?'s':''}`;html+=`<div class="mb-3 ${o.length?'mt-5':''}"><span class="text-xs font-semibold text-gray-400 uppercase tracking-wider">${label}</span></div>${accepted.map(a=>{const b=getBookingForAssignment(a);return b?jobCard(b,a):''}).join('')}`}
  return html
}

function getEarningsForPeriod(days){const cutoff=new Date();cutoff.setDate(cutoff.getDate()-days);const since=cutoff.toISOString().slice(0,10);const today=new Date().toISOString().slice(0,10);return assignments.filter(a=>a.status==='completed'&&a.completed_at&&a.completed_at.slice(0,10)>=since).reduce((s,a)=>{const b=bookingsById[a.booking_id];return s+(b?.booking_details?.price||0)},0)}

function renderEarningsContent(){
  if(loading)return renderAppLoading()
  const completed=assignments.filter(a=>a.status==='completed').sort((a,b)=>(b.completed_at||'').localeCompare(a.completed_at||''))
  const todayEarnings=getTodayEarnings()
  const weekEarnings=getEarningsForPeriod(7)
  const monthEarnings=getEarningsForPeriod(30)
  const total=completed.reduce((s,a)=>{const b=bookingsById[a.booking_id];return s+(b?.booking_details?.price||0)},0)
  return`<div class="space-y-4"><div class="grid grid-cols-3 gap-3"><div class="bg-white rounded-xl p-3 shadow-sm border border-gray-100 text-center"><p class="text-[10px] font-semibold text-gray-400 uppercase tracking-wider">Today</p><p class="text-lg font-bold text-brand-700 mt-1">$${todayEarnings}</p></div><div class="bg-white rounded-xl p-3 shadow-sm border border-gray-100 text-center"><p class="text-[10px] font-semibold text-gray-400 uppercase tracking-wider">Week</p><p class="text-lg font-bold text-brand-700 mt-1">$${weekEarnings}</p></div><div class="bg-white rounded-xl p-3 shadow-sm border border-gray-100 text-center"><p class="text-[10px] font-semibold text-gray-400 uppercase tracking-wider">Month</p><p class="text-lg font-bold text-brand-700 mt-1">$${monthEarnings}</p></div></div><div class="bg-white rounded-xl p-4 shadow-sm border border-gray-100 flex items-center justify-between"><span class="text-sm font-semibold text-gray-800">Total earned</span><span class="text-xl font-bold text-brand-700">$${total}</span></div>${completed.length?`<div class="mt-2"><span class="text-xs font-semibold text-gray-400 uppercase tracking-wider">${completed.length} completed job${completed.length!==1?'s':''}</span><div class="mt-3 space-y-2">${completed.slice(0,15).map(a=>{const b=bookingsById[a.booking_id];if(!b)return'';const date=b.booking_details?.preferred_date;return`<div class="bg-white rounded-xl p-3 shadow-sm border border-gray-100 flex items-center gap-3"><div class="w-10 h-10 rounded-lg bg-brand-50 flex items-center justify-center shrink-0"><span class="text-sm font-bold text-brand-700">$${b.booking_details?.price||0}</span></div><div class="flex-1 min-w-0"><p class="text-sm font-semibold text-gray-800 truncate">${b.customer_info?.name||'Unknown'}</p><p class="text-xs text-gray-400">${b.booking_details?.service_type||'Service'}${date?' &middot; '+formatDate(date):''}</p></div><span class="text-xs font-medium text-brand">+$${b.booking_details?.price||0}</span></div>`}).join('')}</div></div>`:`<div class="text-center text-gray-400 py-8"><p class="text-sm">No completed jobs yet</p></div>`}</div>`
}

function renderScheduleContent(){
  const acceptedBookings=getAcceptedBookings()
  const upcoming=acceptedBookings.filter(b=>b.booking_details?.preferred_date).sort((a,b)=>a.booking_details.preferred_date.localeCompare(b.booking_details.preferred_date)).filter(b=>b.booking_details.preferred_date>=new Date().toISOString().slice(0,10))
  const listViewHTML=`<div class="flex-1 overflow-y-auto px-4 pt-3 pb-4"><div class="flex items-center justify-between mb-3"><span class="text-xs font-semibold text-gray-400 uppercase tracking-wider">${upcoming.length} upcoming job${upcoming.length!==1?'s':''}</span></div>${!upcoming.length?`<div class="text-center text-gray-400 py-16"><svg class="w-12 h-12 mx-auto mb-3 text-gray-300" viewBox="0 0 24 24">${iconsSvg.calendar}</svg><p class="text-sm">No upcoming jobs</p></div>`:(()=>{const byDate={};upcoming.forEach(b=>{const d=b.booking_details?.preferred_date||'unknown';if(!byDate[d])byDate[d]=[];byDate[d].push(b)});return Object.entries(byDate).map(([date,jobs])=>`<div class="mb-4"><div class="flex items-center gap-2 mb-2 px-0.5"><div class="w-2 h-2 rounded-full bg-brand"></div><span class="text-xs font-bold text-gray-500">${formatDate(date)}</span><span class="text-[10px] text-gray-400 ml-auto">${jobs.length} job${jobs.length>1?'s':''}</span></div><div class="space-y-2">${jobs.map(b=>{const sc=statusConfig[b.status]||statusConfig.pending;const addr=b.location_info;return`<div class="schedule-job-card bg-white rounded-xl border border-gray-100 overflow-hidden active:scale-[0.98] transition-transform cursor-pointer shadow-sm" data-booking-id="${b.id}"><div class="flex items-stretch"><div class="w-1 ${sc.dot} shrink-0"></div><div class="flex-1 p-3.5"><div class="flex items-start justify-between gap-2"><div class="min-w-0"><p class="text-sm font-semibold text-gray-800 truncate">${b.customer_info?.name||'Unknown'}</p><p class="text-xs text-gray-400 mt-0.5">${addr?.address?addr.address.split(',')[0]:addr?.city||''}${addr?.unit_number?' #'+addr.unit_number:''}</p></div><span class="text-xs font-bold ${sc.text} bg-gray-50 px-2 py-0.5 rounded-full shrink-0">${b.booking_details?.preferred_time||''}</span></div><div class="flex items-center gap-2 mt-2"><svg class="w-3.5 h-3.5 text-gray-300" viewBox="0 0 24 24"><path d="M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/><circle cx="12" cy="10" r="3" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg><span class="text-xs text-gray-400">${addr?.city||''},${addr?.state||''} ${addr?.zip_code||''}</span></div></div></div></div>`}).join('')}</div></div>`).join('')})()}</div>`
  return`<div class="flex flex-col h-full relative"><div class="flex-1 p-3 ${scheduleViewMode==='list'?'hidden':''}"><div class="w-full h-full rounded-2xl overflow-hidden border-2 border-gray-300 bg-gray-200" id="map-container"></div></div><div class="absolute top-6 right-6 z-[1000] flex items-center gap-1"><button id="view-map" class="text-xs px-3 py-1.5 rounded-full font-medium shadow-md transition ${scheduleViewMode==='map'?'bg-brand text-white':'bg-white text-gray-700 border border-gray-200/50'}">Map</button><button id="view-list" class="text-xs px-3 py-1.5 rounded-full font-medium shadow-md transition ${scheduleViewMode==='list'?'bg-brand text-white':'bg-white text-gray-700 border border-gray-200/50'}">List</button></div>${scheduleViewMode==='list'?listViewHTML:''}</div>`
}

function renderSettingsContent(){
  const statusLabel=driver?.status?driver.status.charAt(0).toUpperCase()+driver.status.slice(1):'Unknown'
  const statusColor=driver?.status==='approved'?'text-brand':driver?.status==='suspended'?'text-red-600':'text-amber-600'
  return`<div class="space-y-4 pt-2"><div class="bg-white rounded-xl shadow-sm border border-gray-100 p-4 flex items-center gap-4"><div class="w-12 h-12 bg-brand-100 rounded-full flex items-center justify-center text-brand-700 font-bold text-lg">${(driver?.full_name||session.user.email||'?')[0].toUpperCase()}</div><div><p class="font-semibold text-gray-800">${driver?.full_name||session.user.email}</p><p class="text-xs ${statusColor} font-medium">${statusLabel} driver</p></div></div>${serviceAreas.length?`<div class="bg-white rounded-xl shadow-sm border border-gray-100 p-4"><h3 class="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-2">Service areas</h3><p class="text-sm text-gray-700">${serviceAreas.join(', ')}</p></div>`:''}<div class="bg-white rounded-xl shadow-sm border border-gray-100 divide-y divide-gray-50"><div class="flex items-center gap-3 p-4 text-sm text-gray-500"><svg class="w-5 h-5" viewBox="0 0 24 24"><rect x="2" y="3" width="20" height="14" rx="2" ry="2" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/><line x1="8" y1="21" x2="16" y2="21" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/><line x1="12" y1="17" x2="12" y2="21" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg><span>App Version</span><span class="ml-auto text-xs text-gray-400">1.1.0</span></div></div><button id="logout-btn" class="w-full bg-red-50 text-red-600 font-semibold py-3 rounded-xl hover:bg-red-100 active:scale-[0.98] transition text-sm border border-red-200">Sign Out</button></div>`
}

function renderApp(){
  const params=new URLSearchParams(window.location.hash.slice(1))
  const active=params.get('tab')||'schedule'
  const offersCount=getOffers().length
  const contentMap={jobs:()=>renderJobsContent(),earnings:()=>renderEarningsContent(),schedule:()=>renderScheduleContent(),settings:()=>renderSettingsContent()}
  const isApproved=driver?.status==='approved'
  const showMainApp=!loading&&isApproved
  let mainContent
  if(loading)mainContent=renderAppLoading()
  else if(isApproved)mainContent=(contentMap[active]||contentMap.schedule)()
  else mainContent=renderPendingScreen()
  document.querySelector('#app').innerHTML=`<div class="flex flex-col h-dvh max-w-md mx-auto bg-gray-100 shadow-xl relative overflow-hidden"><header class="bg-secondary px-5 pt-12 pb-4 shrink-0"><div class="flex items-center justify-between"><button id="avatar-btn" class="w-10 h-10 rounded-full bg-white/15 flex items-center justify-center text-white font-bold text-sm overflow-hidden shrink-0">${driver?.photo_url?`<img src="${driver.photo_url}" class="w-full h-full object-cover" alt=""/>`:(driver?.full_name||'D')[0].toUpperCase()}<input type="file" id="avatar-upload" accept="image/*" class="hidden"/></button><div class="w-10 h-10 rounded-full bg-white/15 flex items-center justify-center"><span class="pl-bar" style="background:rgba(255,255,255,0.5);width:0.5rem;height:1.2rem;border-radius:1px"></span><span class="pl-bar pl-bar-2" style="background:rgba(255,255,255,0.5);width:0.5rem;height:1.2rem;border-radius:1px"></span></div><div class="bg-white/10 rounded-xl px-4 py-2.5 text-center"><p class="text-[9px] font-semibold text-white/50 uppercase tracking-widest">Today's earnings</p><p class="text-xl font-bold text-white">$${getTodayEarnings()}</p></div></div></header><main class="flex-1 ${active==='schedule'?'p-0':'overflow-y-auto p-4'} relative">${mainContent}</main>${showMainApp?`<nav class="bg-white border-t border-gray-200 flex shrink-0">${tabs.map(tab=>{const isActive=tab.id===active;const badge=tab.id==='jobs'&&offersCount>0?`<span class="absolute -top-1 -right-1 w-4 h-4 bg-red-500 text-white text-[10px] font-bold rounded-full flex items-center justify-center">${offersCount}</span>`:'';return`<a href="#tab=${tab.id}" class="relative flex-1 flex flex-col items-center gap-0.5 py-2 text-xs font-medium transition-colors ${isActive?'text-brand':'text-gray-400 hover:text-gray-600'}"><span class="relative"><svg class="w-6 h-6" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="${isActive?2.5:1.8}" stroke-linecap="round" stroke-linejoin="round">${iconsSvg[tab.icon]}</svg>${badge}</span><span>${tab.label}</span></a>`}).join('')}</nav>`:''}</div>`
  bindEvents(active,showMainApp)
}

function bindEvents(active,showApp=true){
  if(!showApp){const b=document.getElementById('logout-btn');if(b)b.addEventListener('click',async()=>{await supabase.auth.signOut();session=null;driver=null;window.location.hash='';renderLoginPage()});return}
  document.getElementById('avatar-btn')?.addEventListener('click',()=>{document.getElementById('avatar-upload')?.click()})
  document.getElementById('avatar-upload')?.addEventListener('change',async(e)=>{const file=e.target.files?.[0];if(!file||!driver)return;const reader=new FileReader();reader.onload=async(ev)=>{const dataUrl=ev.target.result;const base64=dataUrl.split(',')[1];const binary=atob(base64);const bytes=new Uint8Array(binary.length);for(let i=0;i<binary.length;i++)bytes[i]=binary.charCodeAt(i);const blob=new Blob([bytes],{type:'image/png'});const path=`avatars/${driver.id}.png`;const{error}=await supabase.storage.from('booking-photos').upload(path,new File([blob],'avatar.png',{type:'image/png'}),{contentType:'image/png',upsert:true});if(error){alert('Upload failed');return};const{data:urlData}=supabase.storage.from('booking-photos').getPublicUrl(path);await supabase.from('drivers').update({photo_url:urlData.publicUrl}).eq('id',driver.id);driver={...driver,photo_url:urlData.publicUrl};renderApp()};reader.readAsDataURL(file)})
  if(active==='jobs'&&!loading){
    document.querySelectorAll('.accept-offer-btn').forEach(btn=>btn.addEventListener('click',async(e)=>{e.stopPropagation();const id=btn.dataset.assignmentId;btn.disabled=true;const{error}=await supabase.rpc('accept_job_assignment',{p_assignment_id:id});if(error){alert(error.message);btn.disabled=false;return};await loadDriverData();window.location.hash='tab=jobs'}))
    document.querySelectorAll('.decline-offer-btn').forEach(btn=>btn.addEventListener('click',async(e)=>{e.stopPropagation();const id=btn.dataset.assignmentId;if(!confirm('Decline this job offer?'))return;btn.disabled=true;const{error}=await supabase.rpc('decline_job_assignment',{p_assignment_id:id});if(error)alert(error.message);await loadDriverData()}))
    document.querySelectorAll('.job-card').forEach(c=>c.addEventListener('click',()=>{const id=c.dataset.bookingId;const aid=c.dataset.assignmentId;selectedBooking=bookingsById[id];selectedAssignment=aid?assignments.find(a=>a.id===aid):null;if(selectedBooking)showBookingDetail()}))
  }
  if(active==='schedule'){
    document.getElementById('view-map').addEventListener('click',()=>{scheduleViewMode='map';renderApp()})
    document.getElementById('view-list').addEventListener('click',()=>{scheduleViewMode='list';renderApp()})
    if(scheduleViewMode==='map')initScheduleMap()
    document.querySelectorAll('.schedule-job-card').forEach(c=>c.addEventListener('click',()=>{const id=c.dataset.bookingId;selectedBooking=bookingsById[id];selectedAssignment=assignments.find(a=>a.booking_id===id&&(a.status==='accepted'||a.status==='in_progress'||a.status==='completed'))||null;if(selectedBooking)showBookingDetail()}))
  }
  if(active==='settings'){const b=document.getElementById('logout-btn');if(b)b.addEventListener('click',async()=>{await supabase.auth.signOut();session=null;window.location.hash='';renderLoginPage()})}
}

function showConfirm(message,confirmText='Confirm',cancelText='Cancel',danger=false){return new Promise(resolve=>{const main=document.querySelector('main');if(!main){resolve(false);return};const overlay=document.createElement('div');overlay.className='absolute inset-0 z-[4000] flex items-center justify-center bg-black/40 animate-fade-in';const icon=danger?'<circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/>':'<path d="M22 11.08V12a10 10 0 1 1-5.93-9.14"/><polyline points="22 4 12 14.01 9 11.01"/>';overlay.innerHTML=`<div class="bg-white rounded-2xl shadow-2xl mx-6 w-full max-w-xs overflow-hidden animate-scale-in"><div class="p-6 text-center"><div class="w-12 h-12 ${danger?'bg-red-100':'bg-brand-100'} rounded-full flex items-center justify-center mx-auto mb-4"><svg class="w-6 h-6 ${danger?'text-red-600':'text-brand'}" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round">${icon}</svg></div><p class="text-sm text-gray-700 font-medium leading-relaxed">${message}</p></div><div class="flex border-t border-gray-100"><button class="cancel-btn flex-1 py-3.5 text-sm font-semibold text-gray-500 hover:bg-gray-50 active:bg-gray-100 transition">${cancelText}</button><button class="confirm-btn flex-1 py-3.5 text-sm font-semibold border-l border-gray-100 ${danger?'text-red-600 hover:bg-red-50 active:bg-red-100':'text-brand hover:bg-brand-50 active:bg-brand-100'} transition">${confirmText}</button></div></div>`;main.appendChild(overlay);overlay.querySelector('.cancel-btn').addEventListener('click',()=>{overlay.remove();resolve(false)});overlay.querySelector('.confirm-btn').addEventListener('click',()=>{overlay.remove();resolve(true)});overlay.addEventListener('click',e=>{if(e.target===overlay){overlay.remove();resolve(false)}})})}

function bindBookingDetailEvents(){document.getElementById('close-detail')?.addEventListener('click',closeBookingDetail);document.getElementById('start-job-btn')?.addEventListener('click',async()=>{if(!selectedAssignment||selectedAssignment.status!=='accepted')return;if(!await showConfirm('Are you sure you want to start this job now?','Start Job','Cancel'))return;const btn=document.getElementById('start-job-btn');btn.disabled=true;btn.textContent='Starting...';const{error}=await supabase.rpc('start_job_assignment',{p_assignment_id:selectedAssignment.id});if(error){alert(error.message);btn.disabled=false;btn.textContent='Start Job';return};selectedAssignment={...selectedAssignment,status:'in_progress',updated_at:new Date().toISOString()};const idx=assignments.findIndex(a=>a.id===selectedAssignment.id);if(idx!==-1)assignments[idx]=selectedAssignment;refreshBookingDetail()});document.getElementById('complete-job-btn')?.addEventListener('click',async()=>{if(!selectedAssignment||selectedAssignment.status!=='in_progress')return;if(!await showConfirm('Are you sure you want to mark this job complete?','Complete','Cancel'))return;showCompletionForm()})}

function showBookingDetail(){const main=document.querySelector('main');if(!main||!selectedBooking)return;main.insertAdjacentHTML('beforeend',renderBookingDetail(selectedBooking,selectedAssignment));setTimeout(bindBookingDetailEvents,0)}

function refreshBookingDetail(){const old=document.querySelector('main > .animate-slide-up');if(old){const removed=old.parentNode.removeChild(old);setTimeout(()=>{const main=document.querySelector('main');if(!main||!selectedBooking)return;main.insertAdjacentHTML('beforeend',renderBookingDetail(selectedBooking,selectedAssignment));setTimeout(bindBookingDetailEvents,0)},50)}else{const main=document.querySelector('main');if(!main||!selectedBooking)return;main.insertAdjacentHTML('beforeend',renderBookingDetail(selectedBooking,selectedAssignment));setTimeout(bindBookingDetailEvents,0)}}

let completionPhotos=[]
let completionRating=0
let completionSignature=null

function renderCompletionForm(booking,assignment){
  const customerName=booking.customer_info?.name||''
  return`<div class="absolute inset-0 z-[3000] bg-gray-100 flex flex-col animate-slide-up" id="completion-form"><header class="bg-white border-b border-gray-100 text-gray-800 px-4 pt-3 pb-3 shrink-0"><div class="flex items-center gap-3"><button id="close-completion" class="w-8 h-8 bg-gray-100 rounded-lg flex items-center justify-center active:scale-90 transition-transform"><svg class="w-5 h-5 text-gray-500" viewBox="0 0 24 24">${iconsSvg.chevronLeft}</svg></button><div><h1 class="text-sm font-semibold">Complete Job</h1><p class="text-xs text-gray-500">${customerName} &mdash; ${booking.booking_details?.service_type||''}</p></div></div></header><main class="flex-1 overflow-y-auto p-4 space-y-4 pb-32"><div class="bg-white rounded-xl p-4 shadow-sm border border-gray-100"><h3 class="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-3">Completion Photo</h3><div id="photo-previews" class="grid grid-cols-3 gap-2 mb-3"></div><label class="flex items-center justify-center gap-2 w-full py-3 border-2 border-dashed border-gray-200 rounded-xl text-sm text-gray-500 active:bg-gray-50 cursor-pointer"><svg class="w-5 h-5" viewBox="0 0 24 24">${iconsSvg.camera}</svg><span>Take or upload photo</span><input type="file" id="completion-photo" accept="image/*" capture="environment" multiple class="hidden"/></label></div><div class="bg-white rounded-xl p-4 shadow-sm border border-gray-100"><h3 class="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-3">Rate Experience</h3><div id="star-rating" class="flex gap-1">${[1,2,3,4,5].map(i=>`<button class="star-btn w-10 h-10 flex items-center justify-center text-gray-300 active:scale-110 transition-transform" data-rating="${i}"><svg class="w-8 h-8" viewBox="0 0 24 24">${iconsSvg.star}</svg></button>`).join('')}</div></div><div class="bg-white rounded-xl p-4 shadow-sm border border-gray-100"><h3 class="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-3">Customer Name</h3><input type="text" id="completion-customer-name" value="${customerName.replace(/"/g,'&quot;')}" class="w-full px-4 py-3 rounded-xl border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-brand focus:border-transparent"/></div><div class="bg-white rounded-xl p-4 shadow-sm border border-gray-100"><h3 class="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-3">Customer Signature</h3><div id="sig-preview" class="mb-3 hidden"><img src="" class="w-full h-28 object-contain rounded-lg border border-gray-200 bg-white" alt="Signature" id="sig-preview-img"/></div><button id="open-signature" class="w-full py-3 border-2 border-dashed border-gray-200 rounded-xl text-sm text-gray-500 active:bg-gray-50 transition flex items-center justify-center gap-2"><svg class="w-5 h-5" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round"><path d="M12 20h9"/><path d="M16.5 3.5a2.121 2.121 0 0 1 3 3L7 19l-4 1 1-4L16.5 3.5z"/></svg><span id="sig-btn-text">Tap to Sign</span></button><button id="clear-signature" class="hidden mt-2 text-xs text-red-500 font-medium w-full">Clear signature</button></div><div class="bg-white rounded-xl p-4 shadow-sm border border-gray-100"><h3 class="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-3">Notes (optional)</h3><textarea id="completion-notes" rows="3" placeholder="Any notes about this job..." class="w-full px-4 py-3 rounded-xl border border-gray-200 text-sm focus:outline-none focus:ring-2 focus:ring-brand focus:border-transparent resize-none"></textarea></div></main><div class="absolute bottom-0 left-0 right-0 p-4 bg-gradient-to-t from-gray-100 via-gray-100 to-transparent"><button id="submit-completion" class="w-full bg-brand text-white font-semibold py-3.5 rounded-xl active:scale-[0.98] transition text-sm shadow-lg shadow-brand/20">Submit Completion</button></div></div>`
}

function showCompletionForm(){
  const main=document.querySelector('main')
  if(!main||!selectedBooking||!selectedAssignment)return
  completionPhotos=[]
  completionRating=0
  completionSignature=null
  main.insertAdjacentHTML('beforeend',renderCompletionForm(selectedBooking,selectedAssignment))
  setTimeout(()=>{
    document.getElementById('close-completion')?.addEventListener('click',closeCompletionForm)
    document.getElementById('completion-photo')?.addEventListener('change',handlePhotoSelect)
    document.querySelectorAll('.star-btn').forEach(btn=>{btn.addEventListener('click',()=>{completionRating=parseInt(btn.dataset.rating);updateStars()})})
    document.getElementById('open-signature')?.addEventListener('click',showSignaturePad)
    document.getElementById('clear-signature')?.addEventListener('click',clearSignature)
    document.getElementById('submit-completion')?.addEventListener('click',handleCompletionSubmit)
  },0)
}

function closeCompletionForm(){const el=document.getElementById('completion-form');if(el)el.remove()}

function updateStars(){document.querySelectorAll('.star-btn').forEach(btn=>{const r=parseInt(btn.dataset.rating);const svg=btn.querySelector('svg');if(r<=completionRating){btn.classList.replace('text-gray-300','text-amber-400');svg.setAttribute('fill','currentColor')}else{btn.classList.replace('text-amber-400','text-gray-300');svg.setAttribute('fill','none')}})}

function handlePhotoSelect(e){Array.from(e.target.files||[]).forEach(file=>{const reader=new FileReader();reader.onload=ev=>{completionPhotos.push({file,dataUrl:ev.target.result});renderPhotoPreviews()};reader.readAsDataURL(file)})}

function renderPhotoPreviews(){const c=document.getElementById('photo-previews');if(!c)return;c.innerHTML=completionPhotos.map((p,i)=>`<div class="relative aspect-square rounded-lg overflow-hidden bg-gray-100"><img src="${p.dataUrl}" class="w-full h-full object-cover" alt=""/><button class="absolute top-1 right-1 w-5 h-5 bg-red-500 text-white rounded-full flex items-center justify-center text-xs leading-none active:scale-90" data-photo-idx="${i}">&times;</button></div>`).join('');c.querySelectorAll('button').forEach(btn=>{btn.addEventListener('click',e=>{e.stopPropagation();completionPhotos.splice(parseInt(btn.dataset.photoIdx),1);renderPhotoPreviews()})})}

function showSignaturePad(){const main=document.querySelector('main');if(!main)return;main.insertAdjacentHTML('beforeend',`<div class="absolute inset-0 z-[5000] bg-white flex flex-col animate-slide-up" id="sig-pad-overlay"><header class="bg-white border-b border-gray-100 px-4 pt-3 pb-3 shrink-0 flex items-center justify-between"><button id="sig-cancel" class="text-sm font-medium text-gray-500">Cancel</button><span class="text-sm font-semibold text-gray-800">Customer Signature</span><button id="sig-done" class="text-sm font-semibold text-brand">Done</button></header><div class="flex-1 bg-gray-50 relative" style="touch-action:none"><canvas id="sig-canvas" class="absolute inset-0 w-full h-full"></canvas></div><div class="bg-white border-t border-gray-100 px-4 py-2 flex items-center justify-center"><button id="sig-clear-btn" class="text-xs text-red-500 font-medium">Clear</button></div></div>`);setTimeout(()=>{const canvas=document.getElementById('sig-canvas');if(!canvas)return;const rect=canvas.parentElement.getBoundingClientRect();canvas.width=rect.width*2;canvas.height=rect.height*2;const ctx=canvas.getContext('2d');ctx.scale(2,2);ctx.strokeStyle='#111827';ctx.lineWidth=3;ctx.lineCap='round';ctx.lineJoin='round';let drawing=false;function getPos(e){const r=canvas.getBoundingClientRect();const x=(e.touches?e.touches[0].clientX:e.clientX)-r.left;const y=(e.touches?e.touches[0].clientY:e.clientY)-r.top;return{x,y}}function start(e){e.preventDefault();drawing=true;const p=getPos(e);ctx.beginPath();ctx.moveTo(p.x,p.y)}function move(e){if(!drawing)return;e.preventDefault();const p=getPos(e);ctx.lineTo(p.x,p.y);ctx.stroke()}function end(){drawing=false};canvas.addEventListener('mousedown',start);canvas.addEventListener('mousemove',move);canvas.addEventListener('mouseup',end);canvas.addEventListener('mouseleave',end);canvas.addEventListener('touchstart',start,{passive:false});canvas.addEventListener('touchmove',move,{passive:false});canvas.addEventListener('touchend',end);if(completionSignature){const img=new Image();img.onload=()=>{ctx.drawImage(img,0,0,canvas.width/2,canvas.height/2)};img.src=completionSignature};document.getElementById('sig-cancel')?.addEventListener('click',closeSignaturePad);document.getElementById('sig-done')?.addEventListener('click',()=>{const d=canvas.getContext('2d').getImageData(0,0,canvas.width,canvas.height);if(d.data.some(v=>v!==0)){completionSignature=canvas.toDataURL('image/png')};closeSignaturePad();updateSignaturePreview()});document.getElementById('sig-clear-btn')?.addEventListener('click',()=>{canvas.getContext('2d').clearRect(0,0,canvas.width,canvas.height);completionSignature=null})},0)}

function closeSignaturePad(){const el=document.getElementById('sig-pad-overlay');if(el)el.remove()}

function updateSignaturePreview(){const preview=document.getElementById('sig-preview');const img=document.getElementById('sig-preview-img');const btn=document.getElementById('sig-btn-text');const clear=document.getElementById('clear-signature');if(!preview||!img||!btn)return;if(completionSignature){preview.classList.remove('hidden');img.src=completionSignature;btn.textContent='Re-sign';clear.classList.remove('hidden')}else{preview.classList.add('hidden');img.src='';btn.textContent='Tap to Sign';clear.classList.add('hidden')}}

function clearSignature(){completionSignature=null;updateSignaturePreview()}

async function uploadDataUrl(dataUrl,path){const base64=dataUrl.split(',')[1];const binary=atob(base64);const bytes=new Uint8Array(binary.length);for(let i=0;i<binary.length;i++)bytes[i]=binary.charCodeAt(i);const blob=new Blob([bytes],{type:'image/png'});const file=new File([blob],path.split('/').pop(),{type:'image/png'});const{error}=await supabase.storage.from('booking-photos').upload(path,file,{contentType:'image/png',upsert:true});if(error)throw error;const{data:urlData}=supabase.storage.from('booking-photos').getPublicUrl(path);return urlData.publicUrl}

async function handleCompletionSubmit(){const btn=document.getElementById('submit-completion');if(!btn||!selectedAssignment||!driver)return;const customerName=document.getElementById('completion-customer-name')?.value?.trim()||'';const notes=document.getElementById('completion-notes')?.value?.trim()||'';if(completionRating===0){alert('Please select a rating');return}if(!customerName){alert('Please enter the customer name');return};btn.disabled=true;btn.textContent='Submitting...';try{const ts=Date.now();const basePath=`completions/${selectedAssignment.id}`;const photoUrls=[];for(let i=0;i<completionPhotos.length;i++){const url=await uploadDataUrl(completionPhotos[i].dataUrl,`${basePath}/photo_${ts}_${i}.png`);photoUrls.push(url)}let signatureUrl=null;if(completionSignature)signatureUrl=await uploadDataUrl(completionSignature,`${basePath}/signature_${ts}.png`);const{error}=await supabase.rpc('complete_job_with_details',{p_assignment_id:selectedAssignment.id,p_rating:completionRating,p_customer_name:customerName,p_customer_signature_url:signatureUrl,p_notes:notes||null,p_completion_photo_urls:photoUrls});if(error)throw error;closeCompletionForm();closeBookingDetail();await loadDriverData()}catch(err){alert(err.message||'Failed to submit completion');btn.disabled=false;btn.textContent='Submit Completion'}}

function closeBookingDetail(){const d=document.querySelector('main .animate-slide-up');if(d)d.remove();selectedBooking=null;selectedAssignment=null}

async function geocodeAddress(address,city,state,zip){const key=[address,city,state,zip].filter(Boolean).join(', ');if(geocodeCache[key])return geocodeCache[key];const query=encodeURIComponent(key);try{const res=await fetch(`https://nominatim.openstreetmap.org/search?q=${query}&format=json&limit=1&addressdetails=0`);const data=await res.json();if(data.length){const result={lat:parseFloat(data[0].lat),lng:parseFloat(data[0].lon)};geocodeCache[key]=result;return result}}catch{}return null}

function initScheduleMap(){const L=window.L;if(!L)return;const container=document.getElementById('map-container');if(!container)return;container.innerHTML='';const map=L.map('map-container',{zoomControl:false,attributionControl:false}).setView([39.7392,-104.9853],11);L.tileLayer('https://{s}.basemaps.cartocdn.com/light_all/{z}/{x}/{y}{r}.png',{attribution:'&copy; CARTO',maxZoom:18}).addTo(map);const acceptedBookings=getAcceptedBookings().filter(b=>b.booking_details?.preferred_date).sort((a,b)=>a.booking_details.preferred_date.localeCompare(b.booking_details.preferred_date));acceptedBookings.forEach(async(b,i)=>{const addr=b.location_info;const coords=await geocodeAddress(addr?.address,addr?.city,addr?.state,addr?.zip_code);if(!coords)return;const n=i+1;const icon=L.divIcon({className:'map-pin',html:`<div style="position:relative;width:28px;height:36px"><svg width="28" height="36" viewBox="0 0 28 36"><circle cx="14" cy="14" r="14" fill="#ff006e" stroke="#fff" stroke-width="2.5"/></svg><span style="position:absolute;top:8px;left:50%;transform:translateX(-50%);font-size:10px;font-weight:700;color:white;line-height:14px">${n}</span></div>`,iconSize:[28,36],iconAnchor:[14,36],popupAnchor:[0,-34]});const m=L.marker([coords.lat,coords.lng],{icon}).addTo(map);m.bindPopup(`<div style="font-family:system-ui;min-width:140px;padding:2px 0"><p style="font-size:13px;font-weight:700;color:#1f2937;margin:0">${b.customer_info?.name||'Unknown'}</p><p style="font-size:11px;color:#6b7280;margin:2px 0">${b.booking_details?.service_type||'Service'} &middot; ${formatDate(b.booking_details?.preferred_date)}</p><p style="font-size:11px;color:#9ca3af;margin:0">${b.booking_details?.preferred_time||''}</p></div>`);m.on('click',()=>{selectedBooking=b;selectedAssignment=assignments.find(a=>a.booking_id===b.id)||null;showBookingDetail()})});setTimeout(()=>map.invalidateSize(),100)}

function render(){renderApp()}

async function init(){loading=true;const{data}=await supabase.auth.getSession();session=data.session;if(session){await loadDriverData()}else{loading=false;renderLoginPage()}supabase.auth.onAuthStateChange(async(event,newSession)=>{if(event==='INITIAL_SESSION')return;session=newSession;if(session){await loadDriverData()}else{loading=false;driver=null;assignments=[];bookingsById={};window.location.hash='';renderLoginPage()}})}

init()
window.addEventListener('hashchange',()=>{if(session)renderApp()})
